noncompliant:
// Noncompliant - multi-line case clauses make the switch hard to read
switch (day)
{
    case DayOfWeek.Monday:
        Console.WriteLine("Start of work week");
        PrepareForWork();
        SendNotifications();
        break;
    case DayOfWeek.Tuesday:
        Console.WriteLine("Second day");
        DoTuesdayTasks();
        UpdateReports();
        break;
    case DayOfWeek.Wednesday:
        Console.WriteLine("Mid week");
        DoWednesdayTasks();
        ScheduleMeeting();
        break;
    // ... many more multi-line cases
}

compliant:
// Compliant - single-line case clauses, more readable
switch (day)
{
    case DayOfWeek.Monday: HandleMonday(); break;
    case DayOfWeek.Tuesday: HandleTuesday(); break;
    case DayOfWeek.Wednesday: HandleWednesday(); break;
    case DayOfWeek.Thursday: HandleThursday(); break;
    case DayOfWeek.Friday: HandleFriday(); break;
    default: HandleWeekend(); break;
}

// Compliant - using switch expression
var result = day switch
{
    DayOfWeek.Monday => HandleMonday(),
    DayOfWeek.Tuesday => HandleTuesday(),
    DayOfWeek.Wednesday => HandleWednesday(),
    _ => HandleDefault()
};
